pattern.example:
import flask  # Imported but no Flask code in file

def main():
    print("Hello")  # No Flask usage

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/data')
def get_data():
    return jsonify({'data': 'value'})

# Uses Flask but never uses request.cookies or sessions
# CVE-2023-30861 affects cookie parsing, not used here

from flask import Flask, request
app = Flask(__name__)
@app.route('/internal/health') def health(): # This endpoint is internal-only, not exposed # Even if it used cookies, not exploitable return 'OK'

from flask import Flask, request

app = Flask(__name__)

@app.before_request
def validate_input():
    # WAF or input validation prevents malicious cookies
    if not is_valid_cookie(request.cookies):
        abort(400)

@app.route('/api/user')
def user():
    user_id = request.cookies.get('user_id')
    # Validated by before_request, exploitation prevented

from flask import Flask, request
app = Flask(__name__)
@app.route('/api/user') def user(): # Directly uses cookies without validation user_id = request.cookies.get('user_id') # Vulnerable to CVE-2023-30861 return f'User: {user_id}'

